args.sparql:
SELECT ?prizeLabel WHERE {
  wd:Q44183 p:P195 ?statement .
  ?statement ps:P195 ?prize ;
            pq:P585 ?awardDate .
  FILTER (YEAR(?awardDate) = 1983)
  ?prize rdfs:label ?prizeLabel .
  FILTER (LANG(?prizeLabel) = "en")
}

SELECT ?prizeLabel WHERE {
  wd:Q44183 p:P195 ?statement .
  ?statement ps:P195 ?prize ;
            pq:P585 ?awardDate .
  FILTER (STR(?awardDate) = "1983")
  ?prize rdfs:label ?prizeLabel .
  FILTER (LANG(?prizeLabel) = "en")
}
